const { Client } = require('@elastic/elasticsearch');
const express = require('express');
const bodyParser = require('body-parser');

const app = express();
app.use(bodyParser.json());

const client = new Client({
  node: 'http://localhost:9200' // Adjust this to your Elasticsearch instance
});

app.post('/search', async (req, res) => {
  const { query, script } = req.body;

  if (!query || !script) {
    return res.status(400).json({ error: 'Query and script are required.' });
  }

  try {
    const response = await client.search({
      index: 'your_index_name', // Replace with your actual index name
      body: {
        query: {
          function_score: {
            query: {
              match_all: {} // You can replace this with more complex queries if needed
            },
            functions: [
              {
                script_score: {
                  script: {
                    source: `return ${script};` // Use the user-provided script logic here
                  }
                }
              }
            ],
            boost_mode: 'replace' // Adjust this according to your needs
          }
        }
      }
    });

    res.json(response.body);
  } catch (error) {
    console.error('Error executing search:', error);
    res.status(500).json({ error: 'An error occurred while searching.' });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});